import Database from 'better-sqlite3';

const db = new Database('app.db');

// Create table
db.exec(`
  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    tags TEXT DEFAULT '[]',
    created_at TEXT DEFAULT (datetime('now'))
  )
`);

// Prepared statements (safe from SQL injection)
const insert = db.prepare(
  'INSERT INTO bookmarks (url, title, tags) VALUES (?, ?, ?)'
);
insert.run('https://example.com', 'Example', JSON.stringify(['reference']));

// Transaction for bulk inserts
const insertMany = db.transaction((bookmarks) => {
  for (const b of bookmarks) {
    insert.run(b.url, b.title, JSON.stringify(b.tags));
  }
});
